import { ThemeMetadata, StyleObject, Font, ThemeMode } from '@global-theme/core';

type GlobalThemeContext = {
    theme?: Promise<ThemeMetadata | undefined>;
    themeMetadata?: ThemeMetadata;
    styles: Promise<StyleObject>;
    fonts: Promise<Font[]>;
    themeCSS?: string;
    themeMode?: ThemeMode;
    supportsSuperscript?: boolean;
};
type FontsResult = {
    css?: {
        id: string;
        children: string;
    };
    preload?: Set<string>;
};

export type { FontsResult as F, GlobalThemeContext as G };
